// 在十字3格范围内选择一名敌人，造成 1.5 倍攻击力伤害
const target = await Effect.chooseEnemy(actor, {
    range: { shape: "+", n: 4 },
    hintText: "请选择敌人"
  });
if (!target) return false;
const cell = await Effect.chooseCell(target, {
    range: { shape: '+', n: 1 },
    mustEmpty: true,
    passThrough: true,
    hintText: '请选择目标格'
  });
if (!cell) return false;
Effect.teleport(actor, cell.x, cell.y);
var dir = [Math.sign(target.x-actor.x)||1, Math.sign(target.y-actor.y)||0];
Effect.push(actor, target, dir, 1);
actor.skilled = true;
Effect.damage(actor, target, 50, { ignoreDef: true, mul: 1 });
Game.log(actor.name + " 发动技能！");
return true;

const cells = Range.cellsInRange("square", 1, actor.x, actor.y, { includeSelf: false });
for (const c of cells) {
  const t = Game.pieceAt(c.x, c.y);
  if (t && t.alive && t.side !== actor.side)
  Effect.damage(actor, t, 20, { ignoreDef: true ,mul:1});
}
return true;

const choice = await Effect.chooseOption(actor, {
  title: '请选择',
  hintText: '发动分支技能！',
  options: [
    { label: '强攻', desc: '+30 攻击', value: 'atk', aiScore: 60 },
    { label: '治疗', desc: '回 50 血', value: 'heal', aiScore: 80, aiCondition: function(a){ return a.hp < a.maxHp * 0.5; } }
  ]
});
if (!choice) return false;
if (choice.value === 'atk') Effect.modifyAttack(actor, 30, 1);
else if (choice.value === 'heal') Effect.heal(actor, 50);
actor.skilled = true;
return true;

const ally1 = await Effect.chooseAlly(actor, {
    range: { shape: 'r', n: 3 },
    passThrough: true,
    hintText: '请选择友方1'
  });
if (!ally1) return false;
const ally2 = await Effect.chooseAlly(actor, {
    range: { shape: 'r', n: 3 },
    passThrough: true,
    hintText: '请选择友方2',
    filter:function (cell,piece){
      return piece!=ally1
    }
  });
if (!ally2) return false;
Effect.swap(ally1, ally2);
actor.skilled = true;

// 在十字3格范围内选择一名敌人，造成 1.5 倍攻击力伤害
const target = await Effect.chooseEnemy(actor, {
  range: { shape: "r", n: 1 },
  hintText: "请选择敌人"
});
if (!target) return false;
actor.skilled = true;
Effect.damage(actor, target, Effect.getEffectiveAttack(actor), { mul:1 });
var options=[]
for (s of target["skillIds"]){
var skill=Effect.getSkill(target,s)
if(skill.type=="被动")
options.push({label:skill.name,desc:skill.desc,value:skill.id})
}
const choice = await Effect.chooseOption(actor, {
  title: '请选择',
  hintText: '选择被动技能！',
  options:options
});
if (!choice) return false;
Effect.gainTmpSkill(actor, choice.value, { turnsAtStart: 1 });
Game.log(actor.name + " 发动技能！");
return true;

const cell = await Effect.chooseCell(actor, {
  range: { shape: "r", n: 4 },
  mustEmpty: true,
  hintText: "选择突袭目标位置"
});
if (!cell) return false;
actor.skilled = true;
Effect.teleport(actor, cell.x, cell.y);
Game.log(actor.name + " 夜袭敌营！");
const aoeCells = Range.cellsInRange("+", 1, cell.x, cell.y, { includeSelf: true });
let killCount = 0;
for (const c of aoeCells) {
  const enemy = Game.pieceAt(c.x, c.y);
  if (enemy && enemy.alive && enemy.side !== actor.side) {
    const hpBefore = enemy.hp;
    Effect.damage(actor, enemy, Effect.getEffectiveAttack(actor), { mul: 1.2 });
    if (hpBefore > 0 && !enemy.alive) killCount++;
  }
}
Game.log("【劫营】波及 " + aoeCells.length + " 格，击杀 " + killCount + " 人！");
if (killCount > 0) {
  Effect.resetAction(actor);
  Game.log(actor.name + " 劫营得手，士气大振，恢复全部行动！", "turn");
}
return true;
